using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["featureFlags"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false,
            ["analytics"] = true
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/feature-flags",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns only the feature flag settings.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["featureFlags"], new JsonSerializerOptions { WriteIndented = true });
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'environment', 'maxRetries')")] string key)
    {
        var config = new Dictionary<string, object>
        {
            ["environment"] = "production",
            ["maxRetries"] = 3,
            ["timeoutSeconds"] = 30
        };

        return config.TryGetValue(key, out var value)
            ? JsonSerializer.Serialize(value)
            : $"Unknown configuration key: {key}";
    }

    [McpServerTool, Description("Validates whether a JSON string is well-formed.")]
    public static string ValidateJson(
        [Description("The JSON string to validate")] string json)
    {
        try
        {
            JsonDocument.Parse(json);
            return "Valid JSON";
        }
        catch (JsonException ex)
        {
            return $"Invalid JSON: {ex.Message}";
        }
    }
}

